package com.hospital.management.controller;
import com.hospital.management.model.AuthenticatedUser;import com.hospital.management.service.*;import org.junit.jupiter.api.Test;import javax.servlet.RequestDispatcher;import javax.servlet.http.*;import static org.mockito.Mockito.*;
class LoginServletTest {@Test void getForwards()throws Exception{AuthenticationService s=mock(AuthenticationService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);HttpSession session=mock(HttpSession.class);RequestDispatcher d=mock(RequestDispatcher.class);when(q.getSession(false)).thenReturn(null);when(q.getSession(true)).thenReturn(session);when(q.getRequestDispatcher(anyString())).thenReturn(d);new LoginServlet(s).doGet(q,r);verify(d).forward(q,r);}
 @Test void successRenewsSession()throws Exception{AuthenticationService s=mock(AuthenticationService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);HttpSession old=mock(HttpSession.class),fresh=mock(HttpSession.class);AuthenticatedUser u=new AuthenticatedUser(1L,"alex","a@x.invalid","ADMIN");when(q.getParameter("username")).thenReturn("alex");when(q.getParameter("password")).thenReturn("input");when(s.authenticate("alex","input")).thenReturn(AuthenticationResult.success(u));when(q.getSession(false)).thenReturn(old);when(q.getSession(true)).thenReturn(fresh);when(q.getContextPath()).thenReturn("/app");new LoginServlet(s).doPost(q,r);verify(old).invalidate();verify(fresh).setAttribute("authenticatedUser",u);verify(fresh,never()).setAttribute(eq("password"),any());verify(r).sendRedirect("/app/dashboard");}
 @Test void failureForwardsSafely()throws Exception{AuthenticationService s=mock(AuthenticationService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);HttpSession session=mock(HttpSession.class);RequestDispatcher d=mock(RequestDispatcher.class);when(q.getParameter("username")).thenReturn("alex");when(q.getParameter("password")).thenReturn("input");when(s.authenticate(any(),any())).thenReturn(AuthenticationResult.of(AuthenticationResult.Status.INVALID_CREDENTIALS,"Invalid username or password"));when(q.getSession(true)).thenReturn(session);when(q.getRequestDispatcher(anyString())).thenReturn(d);new LoginServlet(s).doPost(q,r);verify(q).setAttribute("errorMessage","Invalid username or password");verify(q,never()).setAttribute(eq("password"),any());verify(d).forward(q,r);}}
